// UART Transmitter - 9600 baud
module johnson_counter (
    input clk,
    input reset,
    output reg [7:0] out
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            out <= 8'b10000000;
        end else begin
            out <= {out[6:0], ~out[7]};
        end
    end
endmodule
